__kernel void srad_kernel(
    const float lambda,
    const int Nr,
    const int Nc,
    const long Ne,
    __global const int* iN,
    __global const int* iS,
    __global const int* jE,
    __global const int* jW,
    __global float* d_dN,
    __global float* d_dS,
    __global float* d_dW,
    __global float* d_dE,
    __global float* c,
    const float q0sqr,
    __global float* d_I)
{
    int k = get_global_id(0);
    if (k >= Ne) return;

    int i = k / Nc;
    int j = k % Nc;

    // Use clamped indices from arrays, no manual clamping here
    int iN_idx = iN[i];
    int iS_idx = iS[i];
    int jW_idx = jW[j];
    int jE_idx = jE[j];

    float Jc = d_I[k];

    float dN = d_I[iN_idx * Nc + j] - Jc;
    float dS = d_I[iS_idx * Nc + j] - Jc;
    float dW = d_I[i * Nc + jW_idx] - Jc;
    float dE = d_I[i * Nc + jE_idx] - Jc;

    d_dN[k] = dN;
    d_dS[k] = dS;
    d_dW[k] = dW;
    d_dE[k] = dE;

    float G2 = (dN * dN + dS * dS + dW * dW + dE * dE) / (Jc * Jc);

    float L = (dN + dS + dW + dE) / Jc;

    float num = 0.5f * G2 - (1.0f / 16.0f) * (L * L);
    float den = 1.0f + 0.25f * L;
    float qsqr = num / (den * den);

    den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
    float c_val = 1.0f / (1.0f + den);

    if (c_val < 0.0f) c_val = 0.0f;
    else if (c_val > 1.0f) c_val = 1.0f;

    c[k] = c_val;
}

__kernel void srad2_kernel(
    const float lambda,
    const int Nr,
    const int Nc,
    const long Ne,
    __global const int* iN,
    __global const int* iS,
    __global const int* jE,
    __global const int* jW,
    __global const float* d_dN,
    __global const float* d_dS,
    __global const float* d_dW,
    __global const float* d_dE,
    __global const float* c,
    __global float* d_I)
{
    int k = get_global_id(0);
    if (k >= Ne) return;

    int i = k / Nc;
    int j = k % Nc;

    int iS_idx = iS[i];
    int jE_idx = jE[j];

    float cN = c[k];
    float cS = c[iS_idx * Nc + j];
    float cW = c[k];
    float cE = c[i * Nc + jE_idx];

    float D = cN * d_dN[k] + cS * d_dS[k] + cW * d_dW[k] + cE * d_dE[k];

    d_I[k] = d_I[k] + 0.25f * lambda * D;
}
